'use client';

import { useEffect, useState } from 'react';
import { useParams } from 'next/navigation';
import Link from 'next/link';
import { Card, CardHeader, CardTitle, CardContent, CardDescription } from '@/components/ui/card';
import { Bot, CheckCircle2, Circle, Clock, KanbanSquare, Loader2, Play, LayoutDashboard, Target, Zap, ArrowRightCircle } from 'lucide-react';
import { Project, Phase } from '@shared/types/project';
import { Task } from '@shared/types/task';
import { Badge } from '@/components/ui/badge';
import { BackgroundAnimation } from '@/components/ui/background-animation';
import { recomputeTaskStatuses } from '@shared/lib/workflow-execution';
import { cn } from '@shared/lib/utils';

export default function ProjectDashboardPage() {
    const { id } = useParams();
    const [projectData, setProjectData] = useState<{ project: Project, phases: Phase[], tasks: Task[] } | null>(null);
    const [nextAction, setNextAction] = useState<{ next_task: Task | null, reasoning: string } | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        let active = true;
        async function fetchDashboard() {
            try {
                const [projectRes, actionRes] = await Promise.all([
                    fetch(`/api/projects/${id}`),
                    fetch(`/api/ai/next-action?project_id=${id}`)
                ]);

                if (!active) return;

                if (projectRes.ok) {
                    const pData = await projectRes.json();
                    setProjectData(pData);
                }

                if (actionRes.ok) {
                    const aData = await actionRes.json();
                    setNextAction(aData);
                }
            } catch (error) {
                console.error("Dashboard failed to load", error);
            } finally {
                if (active) setLoading(false);
            }
        }

        fetchDashboard();
        return () => { active = false; };
    }, [id]);

    if (loading) {
        return (
            <div className="flex-1 flex items-center justify-center p-12 text-muted-foreground">
                <Loader2 className="w-8 h-8 animate-spin" />
            </div>
        );
    }

    if (!projectData) return <div>Project not found.</div>;

    const { project, tasks: initialTasks } = projectData;

    // Load and Merge Local Modifications
    const localUser = typeof window !== 'undefined' ? localStorage.getItem(`workflow_user_tasks_${id}`) : null;
    const localRemoved = typeof window !== 'undefined' ? localStorage.getItem(`workflow_removed_tasks_${id}`) : null;
    const userTasks: Task[] = localUser ? JSON.parse(localUser) : [];
    const removedIds = new Set(localRemoved ? JSON.parse(localRemoved) : []);

    const mergedTasks = [
        ...initialTasks.filter(t => !removedIds.has(t.id)),
        ...userTasks
    ];

    // Added Fallback for Demo Project in case Backend is seeded poorly
    let demoFallback: Task[] = [];
    if (project.is_demo_project && mergedTasks.length === 0) {
        const now = new Date().toISOString();
        demoFallback = [
            {
                id: 't1', title: 'Strategy Briefing', description: 'Align product mission with market needs.',
                status: 'DONE', task_type: 'HUMAN', graph_order: 1, level: 0,
                phase_id: 'p1', task_order: 1, created_at: now, meta: { source: 'AI', is_removed: false }
            },
            {
                id: 't1-a', title: 'Competitor Intelligence', description: 'Analyze market gaps.',
                status: 'DONE', task_type: 'AI', graph_order: 1.1, level: 1, parent_task_id: 't1',
                phase_id: 'p1', task_order: 1, created_at: now, meta: { source: 'AI', is_removed: false }
            },
            {
                id: 't1-b', title: 'Mission Roadmap', description: 'Define execution timeline.',
                status: 'DONE', task_type: 'AI', graph_order: 1.2, level: 1, parent_task_id: 't1',
                phase_id: 'p1', task_order: 2, created_at: now, meta: { source: 'AI', is_removed: false }
            },
            {
                id: 't2', title: 'Data Architecture AI', description: 'Generate optimal schema based on spec.',
                status: 'READY', task_type: 'AI', graph_order: 2, dependency_task_id: 't1', level: 0,
                phase_id: 'p1', task_order: 3, created_at: now, meta: { source: 'AI', is_removed: false }
            },
            {
                id: 't3', title: 'Frontend Scaffold', description: 'Initialize core UI components.',
                status: 'BLOCKED', task_type: 'HUMAN', graph_order: 3, dependency_task_id: 't2', level: 0,
                phase_id: 'p1', task_order: 4, created_at: now, meta: { source: 'AI', is_removed: false }
            }
        ];
    }

    const finalSet = demoFallback.length > 0 ? demoFallback : mergedTasks;
    const recomputed = recomputeTaskStatuses(finalSet);

    // Calculate Progress Stats
    const totalTasks = recomputed.length;
    const completedTasks = recomputed.filter(t => t.status === 'DONE').length;
    const executingTasks = recomputed.filter(t => t.status === 'RUNNING').length;
    const completionPercentage = totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0;

    // 1. Identify "Actionable" tasks from our recomputed set
    const actionable = recomputed.filter(t => t.status === 'READY');

    // Sort actionable tasks by order but prioritize AI
    const sorted = [...actionable].sort((a, b) => {
        if (a.task_type === 'AI' && b.task_type !== 'AI') return -1;
        if (a.task_type !== 'AI' && b.task_type === 'AI') return 1;
        return (a.graph_order || 0) - (b.graph_order || 0);
    });

    const recommended = sorted[0];

    const readyTasksCount = recomputed.filter(t => t.status === 'READY').length;
    const blockedTasksCount = recomputed.filter(t => t.status === 'BLOCKED').length;

    // Groups for the snapshot
    const snapshotGroups = {
        READY: recomputed.filter(t => t.status === 'READY').slice(0, 3),
        RUNNING: recomputed.filter(t => t.status === 'RUNNING').slice(0, 3),
        BLOCKED: recomputed.filter(t => t.status === 'BLOCKED').slice(0, 3),
    };

    return (
        <div className="max-w-full mx-auto px-4 py-3 space-y-4 relative overflow-hidden h-[calc(100vh-80px)] flex flex-col">
            <BackgroundAnimation className="z-[-10] opacity-20" />

            {/* Header Strip: Title & Global CTA */}
            <div className="flex items-center justify-between border-b pb-2">
                <div className="flex items-center gap-3">
                    <h1 className="text-lg font-black tracking-tight flex items-center gap-2">
                        <span className="text-muted-foreground/30 font-bold uppercase text-[10px]">Project /</span>
                        {project.title}
                    </h1>
                    <Badge variant="outline" className="text-[9px] h-5 font-black tracking-widest">{completionPercentage}% DONE</Badge>
                </div>
                <Link href={`/project/${id}/board`} className="h-8 px-4 bg-primary text-primary-foreground rounded-lg text-[10px] font-black uppercase tracking-widest hover:opacity-90 flex items-center gap-2 active:scale-95 transition-all">
                    <KanbanSquare className="w-3.5 h-3.5" />
                    Open Interface
                </Link>
            </div>

            {/* Metrics Strip (Compact row) */}
            <div className="grid grid-cols-4 gap-3">
                {[
                    { label: 'Work Items', val: totalTasks, icon: <Zap className="w-3 h-3" />, color: 'text-blue-500' },
                    { label: 'Completed', val: completedTasks, icon: <CheckCircle2 className="w-3 h-3" />, color: 'text-emerald-500' },
                    { label: 'Ready to start', val: readyTasksCount, icon: <Play className="w-3 h-3" />, color: 'text-primary' },
                    { label: 'Waiting', val: blockedTasksCount, icon: <Clock className="w-3 h-3" />, color: 'text-amber-500' }
                ].map((m, i) => (
                    <Card key={i} className="p-2 border-border/40 shadow-none bg-card/40 flex items-center gap-3">
                        <div className={cn("p-1.5 rounded-md bg-muted/30", m.color)}>{m.icon}</div>
                        <div className="flex flex-col">
                            <span className="text-[9px] font-black text-muted-foreground uppercase tracking-widest leading-none">{m.label}</span>
                            <span className="text-sm font-black mt-0.5">{m.val}</span>
                        </div>
                    </Card>
                ))}
            </div>

            {/* Thin Progress Bar */}
            <div className="px-1 py-1">
                <div className="w-full h-1 bg-muted rounded-full overflow-hidden border border-border/20">
                    <div className="h-full bg-primary transition-all duration-1000" style={{ width: `${completionPercentage}%` }} />
                </div>
            </div>

            {/* Main Action & Snapshot Grid */}
            <div className="grid grid-cols-12 gap-4 flex-1 overflow-hidden">

                {/* Left: Next Strategic Move (Compact) */}
                <div className="col-span-4 flex flex-col gap-3 h-full">
                    <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-primary/60 px-1">Next Strategic Move</h3>
                    <Card className="flex-1 border-primary/20 bg-primary/[0.02] shadow-sm relative overflow-hidden flex flex-col group">
                        {!recommended ? (
                            <div className="flex-1 flex flex-col items-center justify-center text-center p-6 gap-2">
                                <CheckCircle2 className="w-8 h-8 text-emerald-500/40" />
                                <span className="text-xs font-black text-foreground/40 uppercase tracking-widest leading-tight">All Actions Complete</span>
                            </div>
                        ) : (
                            <div className="p-4 flex flex-col h-full gap-4">
                                <div className="space-y-1">
                                    <Badge variant={recommended.task_type === 'AI' ? 'ai' : 'human'} className="text-[8px] h-4 font-black uppercase tracking-widest px-1.5">{recommended.task_type}</Badge>
                                    <h4 className="text-lg font-black tracking-tight leading-tight group-hover:text-primary transition-colors cursor-help" title={recommended.description}>{recommended.title}</h4>
                                </div>
                                <div className="flex-1 bg-background/50 rounded-xl p-3 border border-border/40 text-[11px] leading-relaxed italic text-muted-foreground line-clamp-4">
                                    "{recommended.task_type === 'AI' ? 'Strategist: Handle this autonomous task now to unblock workflow.' : 'Strategist: Human intervention required to validate current path.'}"
                                </div>
                                <Link
                                    href={`/project/${id}/task/${recommended.id}`}
                                    className="w-full bg-primary text-primary-foreground h-10 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 shadow-lg shadow-primary/20 hover:scale-[1.02] active:scale-95 transition-all"
                                >
                                    Engage Agent
                                    <ArrowRightCircle className="w-3.5 h-3.5" />
                                </Link>
                            </div>
                        )}
                    </Card>
                </div>

                {/* Right: Workflow Snapshot (Compact Columns) */}
                <div className="col-span-8 flex flex-col gap-3 h-full overflow-hidden">
                    <div className="flex items-center justify-between px-1">
                        <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground/60">Execution Snapshot</h3>
                        <Link href={`/project/${id}/board`} className="text-[9px] font-black text-primary hover:underline uppercase tracking-widest">View Full Board</Link>
                    </div>
                    <div className="grid grid-cols-3 gap-3 flex-1 overflow-hidden">
                        {[
                            { id: 'READY', label: 'Ready', tasks: snapshotGroups.READY, border: 'border-l-primary' },
                            { id: 'RUNNING', label: 'In Progress', tasks: snapshotGroups.RUNNING, border: 'border-l-blue-500' },
                            { id: 'BLOCKED', label: 'Waiting', tasks: snapshotGroups.BLOCKED, border: 'border-l-amber-500' }
                        ].map(group => (
                            <div key={group.id} className="bg-muted/20 border rounded-xl overflow-hidden flex flex-col border-border/40">
                                <div className="p-2 bg-muted/40 border-b border-border/40 text-[9px] font-black uppercase tracking-widest text-muted-foreground/80">{group.label}</div>
                                <div className="p-2 space-y-2 flex-1 overflow-y-auto overflow-x-hidden custom-scrollbar">
                                    {group.tasks.length === 0 ? (
                                        <div className="h-full flex items-center justify-center text-[9px] text-muted-foreground/30 uppercase font-black">Empty</div>
                                    ) : (
                                        group.tasks.map(t => (
                                            <div
                                                key={t.id}
                                                className={cn(
                                                    "p-2 bg-card rounded-lg border shadow-sm flex flex-col gap-1 hover:border-primary/20 transition-all cursor-pointer",
                                                    group.border,
                                                    t.level === 1 ? "ml-3 border-l-2 pl-3 opacity-90" : ""
                                                )}
                                            >
                                                <div className="flex items-center justify-between gap-2">
                                                    <span className="text-[11px] font-black truncate leading-none text-foreground/80 group-hover:text-foreground">{t.title}</span>
                                                    <Badge className="text-[7px] h-3 px-1 uppercase shrink-0 bg-muted text-muted-foreground border-none font-black">{t.task_type}</Badge>
                                                </div>
                                                <div className="flex items-center justify-between">
                                                    <span className="text-[8px] text-muted-foreground/40 font-black uppercase tracking-tighter">ORD-{t.graph_order}</span>
                                                    <Circle className={cn("w-1.5 h-1.5 fill-current", group.id === 'READY' ? "text-primary" : group.id === 'RUNNING' ? "text-blue-500 animate-pulse" : "text-amber-500/40")} />
                                                </div>
                                            </div>
                                        ))
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

            </div>
        </div>
    );
}
